// NODE: Merge Customers + Tickets from single dataset

try {

  const rows = $input.all().map(i => i.json);

  // Separate customers and tickets
  const customers = rows.filter(r => r.customer_id && r.email);
  const tickets = rows.filter(r => r.ticket_id);

  // Create ticket lookup
  const ticketMap = new Map();

  tickets.forEach(t => {
    if (!ticketMap.has(t.customer_id)) {
      ticketMap.set(t.customer_id, []);
    }

    ticketMap.get(t.customer_id).push({
      ticket_id: t.ticket_id,
      created_date: t.created_date,
      sentiment: t.sentiment,
      resolution_time_hours: parseInt(t.resolution_time_hours || 0),
      category: t.category
    });
  });

  const now = new Date();

  const merged = customers.map(cust => {

    const custTickets = ticketMap.get(cust.customer_id) || [];

    const loginDate = new Date(cust.last_login_date);
    const paymentDate = new Date(cust.last_payment_date);
    const signupDate = new Date(cust.signup_date);

    const daysSinceLogin = Math.floor((now - loginDate) / (1000*60*60*24));
    const daysSincePayment = Math.floor((now - paymentDate) / (1000*60*60*24));
    const tenureMonths = Math.floor((now - signupDate) / (1000*60*60*24*30));

    const negativeTickets = custTickets.filter(t => t.sentiment === "negative").length;

    const avgResolution =
      custTickets.length > 0
        ? custTickets.reduce((sum, t) => sum + t.resolution_time_hours, 0) / custTickets.length
        : 0;

    return {

      // Basic customer info
      customer_id: cust.customer_id,
      email: cust.email,
      company_name: cust.company_name,
      plan_type: cust.plan_type,

      // Tenure
      signup_date: cust.signup_date,
      tenure_months: tenureMonths,

      // Activity
      last_login_date: cust.last_login_date,
      days_since_login: daysSinceLogin,
      monthly_usage: cust.monthly_usage || 0,

      // Payment
      last_payment_date: cust.last_payment_date,
      days_since_payment: daysSincePayment,
      payment_status: cust.payment_status,

      // Support metrics
      total_tickets: custTickets.length,
      negative_tickets: negativeTickets,
      avg_resolution_time: Math.round(avgResolution),

      // Recent tickets
      recent_tickets: custTickets.slice(-5)

    };

  });

  return merged.map(c => ({ json: c }));

} catch (error) {

  console.error("Merge error:", error);

  throw new Error(error.message);

}

// Parse AI output JSON strings for multiple items

const items = $input.all();

return items.map(item => {
  try {

    let raw = item.json.output;

    if (!raw) {
      throw new Error("Missing output field");
    }

    // Extract JSON block (safe in case of extra text)
    const jsonMatch = raw.match(/\{[\s\S]*\}/);

    if (!jsonMatch) {
      throw new Error("No JSON object found in output");
    }

    const parsed = JSON.parse(jsonMatch[0]);

    // Normalize fields
    parsed.churn_risk_score = Math.max(
      0,
      Math.min(100, Number(parsed.churn_risk_score) || 0)
    );

    parsed.risk_level = (parsed.risk_level || "medium").toLowerCase();

    if (!Array.isArray(parsed.churn_signals)) {
      parsed.churn_signals = [];
    }

    if (!Array.isArray(parsed.root_causes)) {
      parsed.root_causes = [];
    }

    parsed.confidence_score = Math.max(
      0,
      Math.min(1, Number(parsed.confidence_score) || 0)
    );

    return {
      json: {
        ...parsed,
        parsing_status: "success"
      }
    };

  } catch (error) {

    return {
      json: {
        parsing_status: "failed",
        error: error.message,
        raw_output: item.json.output
      }
    };

  }
});

// NODE 10: Classify Risk
// Input: Multiple customer items with ai_scoring
// Output: One item per customer with risk classification

const items = $input.all();

function classifyRisk(aiScore) {

  if (aiScore === null || aiScore === undefined) {
    return { tier: "medium", urgency: "engage", score: 50 };
  }

  if (aiScore <= 40) {
    return { tier: "low", urgency: "monitor", score: aiScore };
  }

  if (aiScore <= 70) {
    return { tier: "medium", urgency: "engage", score: aiScore };
  }

  return { tier: "high", urgency: "intervene", score: aiScore };
}

return items.map((item, index) => {

  const cust = item.json;

  const aiScore = cust.ai_scoring?.churn_risk_score ?? null;

  const classification = classifyRisk(aiScore);

  return {
    json: {
      ...cust,

      risk_classification: {
        tier: classification.tier,
        score: Math.round(classification.score),
        urgency: classification.urgency,
        classified_at: new Date().toISOString(),
        action_required: classification.tier !== "low",
        batch_index: index
      }

    }
  };

});

// NODE 6: Validate Data
// Input: customer items
// Output: validated customers

const items = $input.all();

const validated = items.map(item => {
  const cust = item.json;

  const errors = [];
  const warnings = [];

  // Required fields
  if (!cust.customer_id) errors.push("Missing customer_id");
  if (!cust.email) errors.push("Missing email");
  if (!cust.plan_type) errors.push("Missing plan_type");
  if (!cust.payment_status) errors.push("Missing payment_status");

  // Date validation
  const loginDate = new Date(cust.last_login_date);
  if (isNaN(loginDate.getTime())) {
    errors.push("Invalid last_login_date");
  }

  const paymentDate = new Date(cust.last_payment_date);
  if (isNaN(paymentDate.getTime())) {
    errors.push("Invalid last_payment_date");
  }

  // Email validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(cust.email || "")) {
    errors.push("Invalid email format");
  }

  // Plan validation
  const validPlans = ["Free", "Pro", "Enterprise"];
  if (!validPlans.includes(cust.plan_type)) {
    warnings.push(`Unknown plan_type: ${cust.plan_type}`);
  }

  // Payment status validation
  const validStatuses = ["active", "failed", "pending", "expired"];
  if (!validStatuses.includes((cust.payment_status || "").toLowerCase())) {
    warnings.push(`Unknown payment_status: ${cust.payment_status}`);
  }

  // Numeric checks
  if (cust.days_since_login < 0) {
    warnings.push("days_since_login negative");
  }

  return {
    json: {
      ...cust,
      validation: {
        status: errors.length === 0 ? "passed" : "failed",
        errors,
        warnings,
        error_count: errors.length,
        warning_count: warnings.length
      }
    }
  };
});

return validated;

// NODE 7: Calculate Engagement Scores
// Input: validated customer items
// Output: customer items with engagement scores

const items = $input.all();

const calculateLoginRecencyScore = (days) => {
  if (days === 0) return 100;
  if (days <= 7) return 100 - (days * 2);
  if (days <= 30) return 85 - ((days - 7) * 1.5);
  if (days <= 90) return 50 - ((days - 30) * 0.67);
  return Math.max(10, 50 - ((days - 30) * 0.67));
};

const calculateUsageConsistencyScore = (monthlyUsage = 0, activityScore = 50, featureCount = 0) => {
  const usageComponent = Math.min(100, (monthlyUsage / 5000) * 100);
  const activityComponent = activityScore;
  const featureComponent = Math.min(100, (featureCount / 15) * 100);

  return usageComponent * 0.4 + activityComponent * 0.4 + featureComponent * 0.2;
};

const calculateSupportFrustrationScore = (negativeTickets = 0, totalTickets = 0, avgResolutionTime = 0) => {
  if (totalTickets === 0) return 75;

  const negativityRatio = negativeTickets / totalTickets;
  const negativityScore = 100 - (negativityRatio * 100);
  const resolutionPenalty = Math.min(40, (avgResolutionTime / 72) * 40);

  return Math.max(10, negativityScore - resolutionPenalty);
};

const calculatePaymentReliabilityScore = (paymentStatus = "active", daysSincePayment = 0, planType = "Free") => {

  const statusScores = {
    active: 100,
    pending: 60,
    failed: 20,
    expired: 10
  };

  let baseScore = statusScores[paymentStatus.toLowerCase()] ?? 50;

  if (daysSincePayment > 45) {
    baseScore -= Math.min(30, (daysSincePayment - 45) * 0.5);
  }

  if (planType === "Enterprise") {
    baseScore = Math.min(100, baseScore + 5);
  }

  return Math.max(10, baseScore);
};

const results = items.map(item => {

  const cust = item.json;

  if (cust.validation?.status === "failed") {
    return {
      json: {
        ...cust,
        engagement_scores: {
          login_recency_score: 0,
          usage_consistency_score: 0,
          support_frustration_score: 0,
          payment_reliability_score: 0,
          composite_engagement_score: 0
        },
        analysis_skipped: true
      }
    };
  }

  const lrs = calculateLoginRecencyScore(cust.days_since_login);
  const ucs = calculateUsageConsistencyScore(
    cust.monthly_usage,
    cust.activity_score,
    cust.feature_usage_count
  );

  const sfs = calculateSupportFrustrationScore(
    cust.negative_tickets,
    cust.total_tickets,
    cust.avg_resolution_time
  );

  const prs = calculatePaymentReliabilityScore(
    cust.payment_status,
    cust.days_since_payment,
    cust.plan_type
  );

  const ces = (lrs * 0.35 + ucs * 0.30 + sfs * 0.20 + prs * 0.15);

  return {
    json: {
      ...cust,

      engagement_scores: {
        login_recency_score: Math.round(lrs),
        usage_consistency_score: Math.round(ucs),
        support_frustration_score: Math.round(sfs),
        payment_reliability_score: Math.round(prs),
        composite_engagement_score: Math.round(ces)
      },

      churn_risk_indicators: {
        inactive_days_threshold_exceeded: cust.days_since_login > 30,
        low_usage_pattern: cust.monthly_usage < 1000,
        high_support_issues: cust.negative_tickets > 2,
        payment_problems: cust.payment_status !== "active"
      },

      analysis_skipped: false
    }
  };

});

return results;

