// NODE 17: Execution Summary
// Works with multiple customer items and handles null values safely

const items = $input.all();

// Safe execution timestamps
const executionStartRaw = $execution?.startTime;
const executionStart = executionStartRaw ? new Date(executionStartRaw).getTime() : Date.now();
const executionEnd = Date.now();

const durationSeconds = Math.round((executionEnd - executionStart) / 1000);

// Counters
let high = 0;
let medium = 0;
let low = 0;

items.forEach(item => {

  const risk = (item.json?.risk_level || "").toLowerCase();

  if (risk === "high") high++;
  else if (risk === "medium") medium++;
  else if (risk === "low") low++;

});

const total = items.length;

// Safe ISO converter
function safeISO(ts) {
  const d = new Date(ts);
  return isNaN(d.getTime()) ? null : d.toISOString();
}

return [{
  json: {
    execution: {
      id: $execution?.id || null,
      status: "success",
      duration_seconds: durationSeconds,
      started_at: safeISO(executionStart),
      completed_at: safeISO(executionEnd)
    },

    summary: {
      timestamp: new Date().toISOString(),
      workflow_name: "AI Churn Prediction & Retention Engine",

      total_customers_analyzed: total,
      high_risk_customers: high,
      medium_risk_customers: medium,
      low_risk_customers: low,

      retention_actions_triggered: high,
      churn_risk_rate: total ? ((high / total) * 100).toFixed(2) + "%" : "0%",

      success_rate: "100%"
    }
  }
}];
